import { useState, useEffect, useCallback } from "react";
import { ethers } from "ethers";

function WorkerDashboard({ flowArc, address, notify }) {
  const [employerAddr, setEmployerAddr] = useState("");
  const [workerDetails, setWorkerDetails] = useState(null);
  const [earned, setEarned]             = useState("0");
  const [loading, setLoading]           = useState(false);
  const [claiming, setClaiming]         = useState(false);

  const loadWorkerData = useCallback(async () => {
    if (!flowArc || !employerAddr || !ethers.utils.isAddress(employerAddr)) return;
    try {
      const details = await flowArc.getWorkerDetails(employerAddr, address);
      const earnedAmt = await flowArc.getEarnedAmount(employerAddr, address);
      setWorkerDetails({
        name:          details.name,
        active:        details.active,
        monthlySalary: ethers.utils.formatUnits(details.salaryPerSecond.mul(30 * 24 * 3600), 6),
        startTime:     new Date(details.startTime.toNumber() * 1000).toLocaleDateString(),
        lastClaimed:   new Date(details.lastClaimed.toNumber() * 1000).toLocaleString(),
      });
      setEarned(ethers.utils.formatUnits(earnedAmt, 6));
    } catch (e) {
      console.error(e);
    }
  }, [flowArc, employerAddr, address]);

  useEffect(() => {
    if (!employerAddr) return;
    loadWorkerData();
    const interval = setInterval(loadWorkerData, 5000);
    return () => clearInterval(interval);
  }, [loadWorkerData, employerAddr]);

  const claimSalary = async () => {
    if (!employerAddr) return notify("Enter employer address", "error");
    setClaiming(true);
    try {
      const tx = await flowArc.claimSalary(employerAddr);
      await tx.wait();
      notify(`Salary claimed! 🎉`);
      loadWorkerData();
    } catch (e) {
      notify(e.reason || e.message, "error");
    }
    setClaiming(false);
  };

  const checkWorker = async () => {
    if (!ethers.utils.isAddress(employerAddr)) return notify("Invalid employer address", "error");
    setLoading(true);
    await loadWorkerData();
    setLoading(false);
  };

  return (
    <div>
      {/* ── Lookup ── */}
      <div style={styles.card}>
        <h3 style={styles.cardTitle}>🔍 Look Up Your Employment</h3>
        <p style={styles.cardSub}>Enter your employer's wallet address to view your salary details</p>
        <input
          style={styles.input}
          placeholder="Employer Wallet Address (0x...)"
          value={employerAddr}
          onChange={e => setEmployerAddr(e.target.value)}
        />
        <button style={styles.btn} onClick={checkWorker} disabled={loading}>
          {loading ? "Loading..." : "Check Employment →"}
        </button>
      </div>

      {/* ── Worker Details ── */}
      {workerDetails && (
        <div>
          {/* ── Earned Card ── */}
          <div style={styles.earnedCard}>
            <div style={styles.earnedLeft}>
              <div style={styles.earnedLabel}>Total Earned (Unclaimed)</div>
              <div style={styles.earnedAmt}>
                {parseFloat(earned).toFixed(6)} <span style={styles.usdc}>USDC</span>
              </div>
              <div style={styles.streaming}>⚡ Streaming in real-time...</div>
            </div>
            <button
              style={{ ...styles.claimBtn, opacity: parseFloat(earned) > 0 ? 1 : 0.5 }}
              onClick={claimSalary}
              disabled={claiming || parseFloat(earned) === 0}
            >
              {claiming ? "Claiming..." : "Claim Salary 💸"}
            </button>
          </div>

          {/* ── Info Cards ── */}
          <div style={styles.infoGrid}>
            <div style={styles.infoCard}>
              <div style={styles.infoLabel}>👤 Name</div>
              <div style={styles.infoValue}>{workerDetails.name}</div>
            </div>
            <div style={styles.infoCard}>
              <div style={styles.infoLabel}>💵 Monthly Salary</div>
              <div style={styles.infoValue}>{parseFloat(workerDetails.monthlySalary).toFixed(2)} USDC</div>
            </div>
            <div style={styles.infoCard}>
              <div style={styles.infoLabel}>📅 Start Date</div>
              <div style={styles.infoValue}>{workerDetails.startTime}</div>
            </div>
            <div style={styles.infoCard}>
              <div style={styles.infoLabel}>🕐 Last Claimed</div>
              <div style={styles.infoValue}>{workerDetails.lastClaimed}</div>
            </div>
            <div style={styles.infoCard}>
              <div style={styles.infoLabel}>📊 Status</div>
              <div style={{ ...styles.infoValue, color: workerDetails.active ? "#00c48c" : "#ff4d4f" }}>
                {workerDetails.active ? "✅ Active" : "❌ Inactive"}
              </div>
            </div>
            <div style={styles.infoCard}>
              <div style={styles.infoLabel}>⏱️ Per Second</div>
              <div style={styles.infoValue}>
                {(parseFloat(workerDetails.monthlySalary) / (30 * 24 * 3600)).toFixed(8)} USDC
              </div>
            </div>
          </div>
        </div>
      )}

      {/* ── Empty State ── */}
      {!workerDetails && (
        <div style={styles.emptyState}>
          <div style={styles.emptyIcon}>👷</div>
          <p style={styles.emptyText}>Enter your employer's address above to view your salary stream</p>
        </div>
      )}
    </div>
  );
}

const styles = {
  card:        { background: "#1a1a2e", borderRadius: "16px", padding: "24px", marginBottom: "20px" },
  cardTitle:   { fontSize: "18px", fontWeight: "700", marginBottom: "8px", color: "#fff" },
  cardSub:     { color: "#888", marginBottom: "20px", fontSize: "14px" },
  input:       { width: "100%", background: "#0a0a0f", border: "1px solid #2a2a3e", borderRadius: "8px", padding: "12px", color: "#fff", fontSize: "14px", marginBottom: "12px", boxSizing: "border-box" },
  btn:         { background: "#5865f2", color: "#fff", border: "none", padding: "12px 24px", borderRadius: "8px", cursor: "pointer", fontWeight: "600", fontSize: "14px", width: "100%" },
  earnedCard:  { display: "flex", justifyContent: "space-between", alignItems: "center", background: "linear-gradient(135deg, #1a1a2e, #2a1a3e)", borderRadius: "16px", padding: "30px", marginBottom: "20px", border: "1px solid #5865f2" },
  earnedLeft:  {},
  earnedLabel: { fontSize: "13px", color: "#888", marginBottom: "8px" },
  earnedAmt:   { fontSize: "36px", fontWeight: "800", color: "#00c48c" },
  usdc:        { fontSize: "18px", fontWeight: "400", color: "#888" },
  streaming:   { fontSize: "12px", color: "#5865f2", marginTop: "8px" },
  claimBtn:    { background: "#00c48c", color: "#fff", border: "none", padding: "16px 32px", borderRadius: "12px", cursor: "pointer", fontWeight: "700", fontSize: "16px" },
  infoGrid:    { display: "grid", gridTemplateColumns: "1fr 1fr 1fr", gap: "16px", marginBottom: "20px" },
  infoCard:    { background: "#1a1a2e", borderRadius: "12px", padding: "20px" },
  infoLabel:   { fontSize: "12px", color: "#888", marginBottom: "8px" },
  infoValue:   { fontSize: "16px", fontWeight: "600", color: "#fff" },
  emptyState:  { textAlign: "center", padding: "60px 20px" },
  emptyIcon:   { fontSize: "48px", marginBottom: "16px" },
  emptyText:   { color: "#888", fontSize: "16px" },
};

export default WorkerDashboard;
